INSERT INTO public.photos VALUES (21972, 'Plaza de Espaâ”śâ–’a 1941', '"Zaragoza. Plaza de Espaâ”śâ–’a. Noche de nieve". Foto Luker. Nocturna imagen (convertida en postal) de un invierno ocasionalmente mâ”śĂ­s fresco que de ordinario, con precipitaciâ”śâ”‚n en forma de nieve incluida. El fenomenal y natural bucolismo escâ”śÂ®nico parece no ser muy apreciado por los indâ”śÂˇgenas, tal vez al abrigo de sus hogares. Los despejados raâ”śÂˇles tranviarios, y algunas huellas de pisadas, â”śâ•‘nicos rastros de trâ”śĂ­nsito ciudadano. Fuente visual: www.delcampe.net/', 1941, 1941, 1941, 'Anos 40', 'CENTRO', 41.65219700, -0.88107500, '0101000020E6100000A857CA32C431ECBF50C6F8307BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23826303046.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23826303046.webp', 'https://www.flickr.com/photos/zaragozaantigua/23826303046/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22011, 'Pl. de Espaâ”śâ–’a 1944', 'La plaza de Espaâ”śâ–’a desde la altura del edificio del nâ”¬â•‘ 1, esquinero con el Coso Medio. En el centro, la arbolada isleta que circunvalaba el monumento a los Mâ”śĂ­rtires de la Religiâ”śâ”‚n y de la Patria con el aspecto conferido en la reciente reforma de 1942. Tras ella, los tres referenciales inmuebles del este de la plaza: el Banco Zaragozano, el Banco de Espaâ”śâ–’a y la Sociedad de Seguros La Catalana. Al fondo, el Coso Medio. A la derecha, el arranque del paseo de la Independencia. Fuente visual: Ediciones Arribas, en www.delcampe.net/', 1944, 1944, 1944, 'Anos 40', 'CENTRO', 41.65218700, -0.88118000, '0101000020E6100000FB743C66A032ECBF2CF015DD7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42181909880.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42181909880.webp', 'https://www.flickr.com/photos/zaragozaantigua/42181909880/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22015, 'Plaza de Espaâ”śâ–’a c.1941', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 37 del Coso y centrada en latradiconal escena formada por la vista de la ya redenominada plaza de Espaâ”śâ–’a y el arranque del bulevar del paseo de la Independencia. A la derecha, esquinera y antigua sede central del Banco Hispano Americano, poco antes de su remodelaciâ”śâ”‚n integral. A continuaciâ”śâ”‚n, el moderno y algo mâ”śĂ­s vertical inmueble del nâ”¬â•‘ 4 del paseo de la Independencia.', 1941, 1941, 1941, 'Anos 40', 'CENTRO', 41.65234400, -0.88085800, '0101000020E61000006170CD1DFD2FECBFF4DE180280D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49239946827.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49239946827.webp', 'https://www.flickr.com/photos/zaragozaantigua/49239946827/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22174, 'Pl. de Espaâ”śâ–’a 1954', 'Imagen del apoteâ”śâ”‚sico desfile celebrado el dâ”śÂˇa 12 de octubre con motivo del Congreso Nacional Mariano, y que consistiâ”śâ”‚ en una procesionaria compuesta por 27 imâ”śĂ­genes de la Virgen, en representaciâ”śâ”‚n de las provincias peninsulares, desde la sedente imagen del Inmaculado Corazâ”śâ”‚n de Marâ”śÂˇa, hasta la montaraz Virgen de Covadonga. En la fotografâ”śÂˇa, capturada desde el balcâ”śâ”‚n del reciente edificio de la Diputaciâ”śâ”‚n Provincial, uno de los pasos del desfile, atentamente seguido por el Caudillo y Jefe del Estado, Francisco Franco, y su esposa, Carmen Polo. Fuente visual: AMZ.', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.65229400, -0.88113900, '0101000020E6100000575D876A4A32ECBF42B0AA5E7ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31478749752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31478749752.webp', 'https://www.flickr.com/photos/zaragozaantigua/31478749752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22268, 'El Tubo c.1963', 'Archivo fotogrâ”śĂ­fico del diario ABC. Cedida por Rafael Castillejo. El barrio del Tubo de Zaragoza se extiende por el lado sur del antiguo perâ”śÂˇmetro romano, con entrada por plaza de Espaâ”śâ–’a. En la imagen del final de la calle Mâ”śĂ­rtires en su confluencia, al fondo, con la calle Cuatro de Agosto: el Plata, Casa Lac, el Salâ”śâ”‚n Limpiabotas y el letrero indicador del Restaurante Teâ”śâ”‚filo. Mâ”śĂ­s informaciâ”śâ”‚n sobre este rincâ”śâ”‚n de Zaragoza, aquâ”śÂˇ: sites.google.com/site/tausiet/eltubo', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.65248500, -0.88038200, '0101000020E610000018963FDF162CECBFB610E4A084D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14856817971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14856817971.webp', 'https://www.flickr.com/photos/zaragozaantigua/14856817971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22326, 'Plaza de Espaâ”śâ–’a c.1960', 'Imagen de la plaza de Espaâ”śâ–’a en su enlace con el Coso Medio, capturada desde el emboque a la calle Mâ”śĂ­rtires. En primer tâ”śÂ®rmino, el coche 52 de la lâ”śÂˇnea 5 "Torrero". A la derecha, el Banco de Espaâ”śâ–’a. A la izquierda, el Zaragozano. Fuente visual: Diego Navarro Bonilla, amablemente aportada por Rafael Castillejo.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65220800, -0.88042900, '0101000020E610000045662E70792CECBF44183F8D7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16872143796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16872143796.webp', 'https://www.flickr.com/photos/zaragozaantigua/16872143796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22545, 'Serafina y El Plata c.1977', 'Foto Antonio Calvo Pedrâ”śâ”‚s. Puerta de entrada ("Bar") al cafâ”śÂ® cantante El Plata de Zaragoza. Apostada a su vera, la cigarrera del Tubo, conocida como "Serafina", de nombre Herminia Martâ”śÂˇnez Lines.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.65280300, -0.88008900, '0101000020E610000011381268B029ECBF87DD770C8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14968429902.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14968429902.webp', 'https://www.flickr.com/photos/zaragozaantigua/14968429902/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22583, 'Calle Don Jaime I, 1973', 'Câ”śÂ®sar Sâ”śĂ­nchez Vâ”śĂ­zquez. 1973. Imagen de la fachada de la veterana confiterâ”śÂˇa "Sucesor de Aurâ”śÂˇa", en la calle Don Jaime I, 9. Abierta en los albores del siglo XX, cerrâ”śâ”‚ definitivamente en 1982. Fuente visual: www.facebook.com/groups/fotosantiguasdezaragoza/792846500...', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65228300, -0.87968900, '0101000020E610000089D4B48B6926ECBF4E5E64027ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15600539992.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15600539992.webp', 'https://www.flickr.com/photos/zaragozaantigua/15600539992/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22674, 'Calle Mâ”śĂ­rtires c.1972', 'Foto: Coyne. Procesiâ”śâ”‚n de Semana Santa en el tramo del Coso de la plaza de Espaâ”śâ–’a, con la calle de los Mâ”śĂ­rtires al fondo a la derecha. En la esquina (Coso 39), la cafeterâ”śÂˇa Las Vegas 2, donde permaneciâ”śâ”‚ el cafâ”śÂ® Oriental durante seis dâ”śÂ®cadas. Fuente: www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65241500, -0.88061300, '0101000020E61000009DD66D50FB2DECBFBD35B05582D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24306663906.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24306663906.webp', 'https://www.flickr.com/photos/zaragozaantigua/24306663906/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22682, 'El Tubo c.1979', 'Vista de la calle de los Mâ”śĂ­rtires en El Tubo. A la espalda del fotâ”śâ”‚grafo, la plaza de Espaâ”śâ–’a. Fuente: "Zaragoza", Editorial Everest, 1980.', 1979, 1979, 1979, 'Anos 70', 'CENTRO', 41.65250300, -0.88048400, '0101000020E610000028D714C8EC2CECBF5DC5E23785D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26592920796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26592920796.webp', 'https://www.flickr.com/photos/zaragozaantigua/26592920796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22930, 'Pl. de Espaâ”śâ–’a 1981', 'El ruido de sables cobrâ”śâ”‚ forma la tarde del lunes 23 de febrero cuando un grupo de guardiaciviles irrumpiendo en la sesiâ”śâ”‚n plenaria del Congreso de los Diputados. En la imagen, numerosas personas se concentran durante la maâ”śâ–’ana del 24 de febrero en la plaza de Espaâ”śâ–’a, junto a la entrada de la calle de los Mâ”śĂ­rtires (izquierda), esperando la resoluciâ”śâ”‚n del fracasado golpe de Estado. A las 10:00 fueron liberados los diputados retenidos en el Congreso, y a las 12:15 todo habâ”śÂˇa terminado. El viernes 27 de febrero se celebrâ”śâ”‚ en Zaragoza una manifestaciâ”śâ”‚n de repulsa del golpismo convocada por los partidos polâ”śÂˇticos y centrales sindicales mayoritarias, con el lema Por la libertad, la democracia y la Constituciâ”śâ”‚n, entre las plaza de Paraâ”śÂˇso y de San Francisco. Al dâ”śÂˇa siguiente el Jefe del Estado visitâ”śâ”‚ la Academia General Militar, donde se escenificâ”śâ”‚ la tensiâ”śâ”‚n del momento en el tono de los discursos dados. Fuente: Colecciâ”śâ”‚n Antonio Tausiet.', 1981, 1981, 1981, 'Anos 80', 'CENTRO', 41.65233300, -0.88059200, '0101000020E6100000C0D02346CF2DECBF008DD2A57FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31081371963.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31081371963.webp', 'https://www.flickr.com/photos/zaragozaantigua/31081371963/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22950, 'Plaza de Espaâ”śâ–’a c.1981', 'Imagen centrada en el vistoso escaparate de la veterana Joyerâ”śÂˇa Agâ”śâ•ťeras en su establecimiento ubicado en el Coso nâ”¬â•‘ 33, adonde fue a parar ya comenzado el siglo XX desde su fundaciâ”śâ”‚n originaria en la calle de Estâ”śÂ®banes en el aâ”śâ–’o 1870. La joyerâ”śÂˇa perdura hoy en una moderna tienda con taller propio sita en la calle de la Torre Nueva, mientras el local de la imagen ha sido engullido por el esquinero gigante de los frutos secos. La traza decorativa del comercio fue luego eliminada durante una posterior restauraciâ”śâ”‚n integral del inmueble. Fuente visual: joyeriaagueras.es', 1981, 1981, 1981, 'Anos 80', 'CENTRO', 41.65253100, -0.88111500, '0101000020E6100000357BA0151832ECBF2750C42286D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40188654935.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40188654935.webp', 'https://www.flickr.com/photos/zaragozaantigua/40188654935/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22953, 'Calle de la Libertad c.1987', 'Imagen centrada en el inmueble del nâ”śâ•‘mero 16 de la calle de la Libertad, esquinero con la calle de los Estâ”śÂ®banes (a la derecha), una antigua casa de arquitectura tradicional remodelada en profundidad en la segunda mitad del siglo XIX dentro de la entonces imperante estâ”śÂ®tica academicista. Aâ”śâ–’os mâ”śĂ­s tarde, el edificio serâ”śÂˇa derribado y sustituido por uno nuevo que mantuvo la altura, las formas y la distribuciâ”śâ”‚n de vanos. Al fondo de la calle, solar del antiguo nâ”¬â•‘ 14 de la calle de Mâ”śÂ®ndez Nâ”śâ•‘â”śâ–’ez en cuyos bajos se ubicâ”śâ”‚ una parte del gran establecimiento comercial de la empresa "Muebles y Camas Metâ”śĂ­licas Viuda de S. Irisarri", frente a la singular plazuela de la Cabra (referencia a la antigua familia Lacabra). Fuente visual: AMZ.', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.65359700, -0.88008500, '0101000020E6100000B6679604A829ECBFC1E10511A9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42588933695.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42588933695.webp', 'https://www.flickr.com/photos/zaragozaantigua/42588933695/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23019, 'Coso Alto 1992', 'Imagen parcial del veterano edificio del nâ”¬â•‘ 33 del Coso, interesante muestra de la arquitectura eclecticista-academicista de los aâ”śâ–’os 70 del siglo XIX en lo que fuera casa de los marqueses de Nibbiano y barones de Arayzaga. Sobre el gran portâ”śâ”‚n del ingreso principal se conservaba la identificaciâ”śâ”‚n como propiedad del Banco Vitalicio de Espaâ”śâ–’a. En el centro de la imagen, el que fuera durante varias dâ”śÂ®cadas establecimiento comercial de la destacada joyerâ”śÂˇa Agâ”śâ•ťeras. En la parte superior de la imagen aparecen los primeros andamios de obra durante la restauraciâ”śâ”‚n integral del inmueble que, aâ”śâ–’adiendo una altura, lo acondicionarâ”śÂˇa como moderno espacio de oficinas integrado en la nueva fachada del Coso a la plaza de Espaâ”śâ–’a. Fuente visual: AMZ.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65253100, -0.88111500, '0101000020E6100000357BA0151832ECBF2750C42286D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41603118772.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41603118772.webp', 'https://www.flickr.com/photos/zaragozaantigua/41603118772/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23023, 'Calle de los Mâ”śĂ­rtires 1997', 'Imagen del antiguo "Tubo" de la ciudad, en este caso una vista parcial de la calle de los Mâ”śĂ­rtires con el fondo de su desemboque en la calle del Cuatro de Agosto. Esta captura visual muestra algunos de sus referentes establecimientos de restauraciâ”śâ”‚n, comercios y tenderetes antropolâ”śâ”‚gicos que singularizaban este desaparecido entorno provinciano de la Zaragoza que fue, y ya no es. Y todo a pocos segundos de la plaza de Espaâ”śâ–’a.', 1997, 1997, 1997, 'Anos 90', 'CENTRO', 41.65266500, -0.88027900, '0101000020E6100000F2608BDD3E2BECBF361FD7868AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50015671617.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50015671617.webp', 'https://www.flickr.com/photos/zaragozaantigua/50015671617/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23027, 'Calle de los Mâ”śĂ­rtires 1992', 'Crepuscular imagen del tradicional "Tubo" centrada en la seâ”śâ–’era calle de los Mâ”śĂ­rtires capturada desde su emboque por la plaza de Espaâ”śâ–’a, y hasta su cruce al fondo con la calle del Cuatro de Agosto. Aunque esta escena asemeja a tantas y tantas escenas anteriores de este singular espacio de la antigua ciudad, hay indicios en ella de que su tiempo estâ”śĂ­ llegando a su final, como indican por ejemplo los carteles del lado de los impares de esta calle que avisan de "liquidaciâ”śâ”‚n" o "descuento por cese de negocio". La razâ”śâ”‚n: el proyecto residencial y comercial "Puerta Cinegia".', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65252100, -0.88045100, '0101000020E610000039605793A72CECBF037AE1CE85D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50204635811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50204635811.webp', 'https://www.flickr.com/photos/zaragozaantigua/50204635811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23108, 'Calle Cuatro de Agosto 2003', 'Aspecto del rodaje del cortometraje "Casi Mallorca" (Miguel Manteca, 2003) en la calle del Cuatro de Agosto. A la izquierda, edificio de los nâ”śâ•‘meros 5 al 9 en rehabilitaciâ”śâ”‚n, con el acceso al Pasaje de los Giles.', 2003, 2003, 2003, 'Siglo XXI', 'CENTRO', 41.65327300, -0.88105200, '0101000020E61000009C69C2F69331ECBF0E2E1D739ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24629327409.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24629327409.webp', 'https://www.flickr.com/photos/zaragozaantigua/24629327409/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23111, 'Calle Mâ”śĂ­rtires 2003', 'Aspecto de la puerta de acceso al restaurante Casa Lac, el dâ”śÂˇa de su cierre provisional, 1 de agosto de 2003, en el marco de la lucrativa reconversiâ”śâ”‚n del Tubo mediante el abandono durante aâ”śâ–’os. Su publicidad aseguraba que era "el restaurante mâ”śĂ­s antiguo de Espaâ”śâ–’a", por haber sido abierto en 1825, con pastelerâ”śÂˇa en los bajos y comedor isabelino en el primer piso. Su bar modernista fue realizado por Manuel Martâ”śÂˇnez de Ubago en 1925, con escalera de Averly. En 2008 se rehabilitâ”śâ”‚ y volviâ”śâ”‚ a abrir sus puertas de la calle de los Mâ”śĂ­rtires 12.', 2003, 2003, 2003, 'Siglo XXI', 'CENTRO', 41.65280800, -0.88014100, '0101000020E6100000AFCC5B751D2AECBF994869368FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24878519582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24878519582.webp', 'https://www.flickr.com/photos/zaragozaantigua/24878519582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23115, 'Pl. de Espaâ”śâ–’a 2009', 'Imagen de la plaza de Espaâ”śâ–’a en los tiempos que era una rotonda automovilâ”śÂˇstica. Al fondo, a la izquierda, el fino emboque a la calle de los Mâ”śĂ­rtires, y los andamios de obra del edificio del nâ”¬â•‘ 2 de esa calle, integrado visualmente en el vanguardista proyecto "Puerta Cinegia", uno de los caracterâ”śÂˇsticos ejemplos del urbanismo zaragozano del amontonamiento, que a unos encanta, y a otros, no tanto, y que en esta zona hay tantos y tan abundantes ejemplos. Fuente visual: www.flickr.com', 2009, 2009, 2009, 'Siglo XXI', 'CENTRO', 41.65227400, -0.88048200, '0101000020E6100000FAEE5696E82CECBFFB03E5B67DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31003593290.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31003593290.webp', 'https://www.flickr.com/photos/zaragozaantigua/31003593290/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23119, 'Calle Estâ”śÂ®banes 2006', 'En mayo de 2006, el derribo de las tapias de los nâ”śâ•‘meros 11 al 15 de la calle de los Estâ”śÂ®banes mostrâ”śâ”‚ un aspecto novedoso del lugar. Este solar, de 250 metros cuadrados, fue objeto de una instalaciâ”śâ”‚n artâ”śÂˇstica en el marco del programa cultural municipal "En la frontera". Despuâ”śÂ®s, los negocios hosteleros vecinos fueron acondicionando allâ”śÂˇ sus terrazas. Fuente: Heraldo de Aragâ”śâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.65333500, -0.87973400, '0101000020E610000088BCE5EAC726ECBF842A357BA0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31106202764.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31106202764.webp', 'https://www.flickr.com/photos/zaragozaantigua/31106202764/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23272, 'Puerta Cinegia 1808', '"Hallâ”śĂ­ndose un obâ”śâ•‘s atravesado en la calle del Coso por donde mâ”śĂ­s vivos cruzaban los fuegos de una y otra parte, en lo mâ”śĂ­s encendido del combate se arrojaron a tomarle el intrâ”śÂ®pido D. Josâ”śÂ® Fandos y un patriota catalâ”śĂ­n, el cual muriâ”śâ”‚ gloriosamente en la acciâ”śâ”‚n, pero logrado su valeroso intento". Serie Ruinas de Zaragoza, de Juan Gâ”śĂ­lvez (dibujo) y Fernando Brambila (grabado), Câ”śĂ­diz, 1812. Al fondo a la derecha, entre el humo, se ve la Puerta Cinegia, en la entrada del actual Tubo de la plaza de Espaâ”śâ–’a. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65234300, -0.88072900, '0101000020E6100000EB707495EE2EECBF2463B5F97FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15267348332.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15267348332.webp', 'https://www.flickr.com/photos/zaragozaantigua/15267348332/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23603, 'Pl. de la Constituciâ”śâ”‚n 1900', 'Plaza de la Constituciâ”śâ”‚n, con una notable confluencia de lâ”śÂˇneas de tranvâ”śÂˇa de tracciâ”śâ”‚n animal. En primer plano, los tranvâ”śÂˇas de Torrero (el que agarra la curva hacia la derecha) y Circunvalaciâ”śâ”‚n (el que emboca el Coso). Al fondo, el tranvâ”śÂˇa del Arrabal (gira hacia la calle Don Jaime), y el de Bajo Aragâ”śâ”‚n-Madrid. 4 lâ”śÂˇneas de tranvâ”śÂˇa pasando por la Plaza, y tan ricamente. El comercio, boyante; los peatones, tranquilos; la ciudad, "no problemo". Neptuno perduraba tridentino, aunque mal mirado y peor considerado por la intelectualidad catâ”śâ”‚lica local, a la que se la llevaban los demonios y requerâ”śÂˇa quitarlo y sustituirlo por otro mito: el de los mâ”śĂ­rtires cristianos sin nâ”śâ•‘mero. Pocos aâ”śâ–’os despuâ”śÂ®s, asâ”śÂˇ se harâ”śÂˇa.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65237600, -0.88106200, '0101000020E610000080F277EFA831ECBFFF58880E81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14822836179.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14822836179.webp', 'https://www.flickr.com/photos/zaragozaantigua/14822836179/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23616, 'Plaza de Espaâ”śâ–’a 1943', '7 de mayo de 1943. Repatriados de la Divisiâ”śâ”‚n Azul desfilan por la plaza de Espaâ”śâ–’a camino del Pilar. Esta unidad de infanterâ”śÂˇa formâ”śâ”‚ parte del ejâ”śÂ®rcito nazi en su agresiâ”śâ”‚n armada contra la Uniâ”śâ”‚n Soviâ”śÂ®tica. A la izquierda, la entrada de la calle Mâ”śĂ­rtires. A la derecha, el remate del edificio de la Asociaciâ”śâ”‚n de Labradores en el Coso Medio. Fuente Archivo ABC.', 1943, 1943, 1943, 'Anos 40', 'CENTRO', 41.65220800, -0.88042900, '0101000020E610000045662E70792CECBF44183F8D7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20304208583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20304208583.webp', 'https://www.flickr.com/photos/zaragozaantigua/20304208583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23976, 'Plaza de Espaâ”śâ–’a 1974', 'Archivo Municipal Zaragoza. Josâ”śÂ® Jaria Serrano. Mayo 1974. Con motivo de las "Fiestas de Primavera" y el "Coso Blanco", alegre desfile de la banda de mâ”śâ•‘sica de la Policâ”śÂˇa Armada, por la Plaza de Espaâ”śâ–’a. Al fondo, a la derecha, la Câ”śĂ­mara Oficial Provincial Agraria, y el comercio de mâ”śĂ­quinas de coser Alfa. A la izquierda, territorio Omega: la Jefatura Provincial de Zaragoza de FET-JONS.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65268900, -0.88112700, '0101000020E610000046EC13403132ECBFBFBA2A508BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15239204581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15239204581.webp', 'https://www.flickr.com/photos/zaragozaantigua/15239204581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24017, 'El Plata 1987', 'Foto: Eduardo Bayona Estradera. Interior del cafâ”śÂ® cantante El Plata, en la calle del Cuatro de Agosto 23. Fue cerrado en 1992 y reabierto en 2008. Fuente: eduardo-elmundoengeneral.blogspot.com', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.65286200, -0.88016100, '0101000020E610000076DEC666472AECBF8C6665FB90D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24402393888.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24402393888.webp', 'https://www.flickr.com/photos/zaragozaantigua/24402393888/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24053, 'Pl. de la Constituciâ”śâ”‚n 1931', 'Foto: Miguel Marâ”śÂˇn Chivite. Manifestaciâ”śâ”‚n del 1 de mayo de 1931 en la plaza de la Constituciâ”śâ”‚n, con la embocadura del Coso Alto al fondo. A la derecha, pancarta de la Agrupaciâ”śâ”‚n Socialista de Zaragoza. Segâ”śâ•‘n la prensa de la â”śÂ®poca, mâ”śĂ­s de 30.000 personas se unieron a este evento, que tuvo carâ”śĂ­cter mâ”śĂ­s festivo que en anteriores convocatorias, debido al reciente advenimiento de la Segunda Repâ”śâ•‘blica. Fuente: Heraldo de Aragâ”śâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65231700, -0.88113900, '0101000020E6100000575D876A4A32ECBFFACF9A1F7FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31562681580.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31562681580.webp', 'https://www.flickr.com/photos/zaragozaantigua/31562681580/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24070, 'Pl. de la Constituciâ”śâ”‚n 1908', 'Imagen tomada durante la visita del rey Alfonso XIII a Zaragoza los dâ”śÂˇas 14-15 de junio, junto con los infantes Don Fernando y Don Luis Alfonso (a la derecha), cuando formaban parte de la procesiâ”śâ”‚n "câ”śÂˇvica" que acompaâ”śâ–’â”śâ”‚ los restos de Agustina Zaragoza, Manuela Sancho y Casta â”śĂĽlvarez desde el Pilar y hasta la iglesia del Portillo, donde fueron inhumadas. La captura se ha realizado, bajo lluvia, cuando la procesiâ”śâ”‚n estaba llegando a la plaza de la Constituciâ”śâ”‚n desde el Coso alto. Al fondo, tras el monarca y los infantes, los bajos del nâ”¬â•‘ 31 del Coso, remodelado como primera sede del Banco Hispano Americano, y tambiâ”śÂ®n como estudio del fotâ”śâ”‚grafo Gustavo Freudenthal. A la izquierda, la antigua Casa de Coloma. Sobre el firme, tendido de la lâ”śÂˇnea "Circunvalaciâ”śâ”‚n" del tranvâ”śÂˇa. Fuente visual: foto Goâ”śâ–’i, en hemeroteca.abc.es/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65253100, -0.88111500, '0101000020E6100000357BA0151832ECBF2750C42286D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34270292895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34270292895.webp', 'https://www.flickr.com/photos/zaragozaantigua/34270292895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24246, 'Anselmo Coyne 1895', 'Anselmo Marâ”śÂˇa Coyne Barreras naciâ”śâ”‚ en Pamplona en 1830, con ascendencia irlandesa, aprendiâ”śâ”‚ el oficio artesano de la fotografâ”śÂˇa, y se instalâ”śâ”‚ en Zaragoza como asociado a Mariano Jâ”śâ•‘dez Ortiz ("Jâ”śâ•‘dez y Coyne"), en el despacho de â”śÂ®ste, en el privilegiado observatorio de la calle Coso 33, frente a la fuente de Neptuno de la plaza de la Constituciâ”śâ”‚n. Tras la muerte de Jâ”śâ•‘dez, firmâ”śâ”‚ sus trabajos como "Coyne, sucesor de Jâ”śâ•‘dez", hasta que desde 1882 ya figuraba en solitario, hasta su propia muerte en 1896. En 1887 su estudio sufriâ”śâ”‚ un incendio, perdiâ”śÂ®ndose su archivo y material fotogrâ”śĂ­fico, y debiâ”śâ”‚ recomenzar desde cero. Es el iniciador de la saga zaragozana de los Coyne, y su legado visual es invaluable para conocer la ciudad de Zaragoza del â”śâ•‘ltimo tercio del siglo XIX. En la imagen, autorretrato suyo. Fuente visual: Foto Estudio Coyne, AHPZ.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65241800, -0.88079800, '0101000020E61000000C3B8C497F2FECBF2EA9DA6E82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31682025215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31682025215.webp', 'https://www.flickr.com/photos/zaragozaantigua/31682025215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24248, 'Pl. de la Constituciâ”śâ”‚n c.1864', 'Imagen centrada en la afrancesada y pagana fuente de Neptuno, soportada a regaâ”śâ–’adientes tras ser redenominada oficialmente como "de la Princesa". Su ubicaciâ”śâ”‚n en la plaza de la Constituciâ”śâ”‚n, casi donde se alzaba la desaparecida Cruz del Coso encrespaba los â”śĂ­nimos de quienes no pararon hasta conseguir que esta fuente fuera sustituida aâ”śâ–’os despuâ”śÂ®s por un monumento conmemorativo de los mâ”śĂ­rtires de la religiâ”śâ”‚n y la patria, y esta funcional fuente fuera desterrada a parajes menos câ”śÂ®ntricos. De momento, Neptuno seguâ”śÂˇa prestando esencial servicio como abastecedor de agua de boca que redistribuâ”śÂˇan luego aguadores y aguadoras. De fondo, fachada edilicia del Coso, en la que destacan los altos comerciales publicitarios que seâ”śâ–’alan la ubicaciâ”śâ”‚n de los gabinetes fotogrâ”śĂ­ficos de Mariano Jâ”śâ•‘dez Ortâ”śÂˇz, en el nâ”¬â•‘ 33, y el de Santos â”śĂĽlvarez Serra, en el nâ”¬â•‘ 35.', 1864, 1864, 1864, 'Siglo XIX', 'CENTRO', 41.65217000, -0.88071800, '0101000020E6100000F1F3DF83D72EECBF56B77A4E7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34545049520.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34545049520.webp', 'https://www.flickr.com/photos/zaragozaantigua/34545049520/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24251, 'Coso nâ”¬â•‘ 35, c.1863', 'El fotâ”śâ”‚grafo Mariano Jâ”śâ•‘dez y Ortiz posa en un autorretrato realizado en su gabinete sito en el â”śâ•‘ltimo piso del inmueble del Coso nâ”¬â•‘ 35 (antiguo nâ”¬â•‘ 18-19) "frente a la fuente" de la Princesa o de Neptuno en la plaza de la Constituciâ”śâ”‚n. Este zaragozano pionero de la fotografâ”śÂˇa, hasta su fallecimiento en 1874 es autor de un singular repertorio de imâ”śĂ­genes de la ciudad y algunos de sus habitantes. Prematuramente muerto, Anselmo Marâ”śÂˇa Coyne Barreras mantendrâ”śÂˇa durante unos aâ”śâ–’os la actividad fotogrâ”śĂ­fica de su gabinete (establecido en el nâ”¬â•‘ 33 del Coso) mediante la Sociedad Industrial Jâ”śâ•‘dez y Coyne.', 1863, 1863, 1863, 'Siglo XIX', 'CENTRO', 41.65248100, -0.88070800, '0101000020E61000000E6B2A8BC22EECBF7521567F84D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49802909812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49802909812.webp', 'https://www.flickr.com/photos/zaragozaantigua/49802909812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24253, 'Coyne y Tramullas 1909', 'Ignacio Coyne Lapetra y Antonio de Padua Tramullas posan en el estudio fotogrâ”śĂ­fico de Coyne en la plaza de la Constituciâ”śâ”‚n, en los tiempos en que el primero tenâ”śÂˇa abierto en la calle de San Miguel, en el tramo de los impares entre el paseo de la Constituciâ”śâ”‚n y la calle de los Sitios, el Cinematâ”śâ”‚grafo Coyne, primer local cinematogrâ”śĂ­fico estable de Zaragoza. Con el tiempo, allâ”śÂˇ llegâ”śâ”‚ a exhibir producciones propias, de las que sâ”śâ”‚lo nos han llegado los tâ”śÂˇtulos. El barcelonâ”śÂ®s Tramullas llegâ”śâ”‚ a Zaragoza en 1899 y comenzâ”śâ”‚ trabajando como electricista en la empresa termoelâ”śÂ®ctrica Electra Peral Zaragozana. En 1905 Ignacio Coyne inaugurâ”śâ”‚ su referido cine y Tramullas se cambiâ”śâ”‚ de acera para trabajar allâ”śÂˇ como operador de cabina, colaborando con Coyne de forma creciente, viajando ambos por pueblos y ciudades dando a conocer el nuevo Cine Parlante Coyne. En 1909, aâ”śâ–’o de esta imagen, se trasladaron al escenario bâ”śÂ®lico de Melilla durante la guerra de Marruecos, y allâ”śÂˇ rodaron varios noticiarios grâ”śĂ­ficos que se distribuyeron por toda Europa. Su colaboraciâ”śâ”‚n perdurâ”śâ”‚ hasta 1912, cuando prematuramente falleciâ”śâ”‚ Coyne y Tramullas pasâ”śâ”‚ a dedicarse en exclusiva a su propia productora, Sallumart (su apellido, al revâ”śÂ®s) Films, que habâ”śÂˇa creado en 1910, y prosigue en la tarea de filmar los principales acontecimientos ciudadanos y reportajes de actualidad, incluyendo alguna obra de ficciâ”śâ”‚n, como "El diablo estâ”śĂ­ en Zaragoza" (1921), y reportajes documentales de temâ”śĂ­tica agrâ”śÂˇcola, como "El primer tractor en Zaragoza" (1915), realizado para la Granja Agrâ”śÂˇcola.', 1909, 1909, 1909, 'Anos 1900', 'CENTRO', 41.65252100, -0.88084800, '0101000020E61000007DE71725E82FECBF037AE1CE85D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50137271611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50137271611.webp', 'https://www.flickr.com/photos/zaragozaantigua/50137271611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24349, 'Torre de San Gil 1992', 'Torre de la iglesia de San Gil Abad tomada por Jasolo en 1992. Se restaurâ”śâ”‚ en 2006. Fuente: zaragozaciudad.net/zaragozafluye/2013/011101-torre-de-la-...', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65309300, -0.87971000, '0101000020E610000066DAFE959526ECBF8E1F2A8D98D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14846037079.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14846037079.webp', 'https://www.flickr.com/photos/zaragozaantigua/14846037079/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24864, 'Pl. de la Constituciâ”śâ”‚n c.1901', 'Imagen nival de la plaza de la Constituciâ”śâ”‚n capturada al nivel peatonal, y centrada en el arranque de la calle de la Independencia, al fondo. A la derecha, vista parcial de la funcional fuente del pagano Neptuno, de la que seguâ”śÂˇa fluyendo el vital lâ”śÂˇquido, antes de ser erradicada y sustituida por una fuente ornamental mâ”śĂ­s ortodoxa y canâ”śâ”‚nica. En primer plano, posiblemente uno de los aguadores que, tras reponer materia prima en la fuente, se encamina con su vehâ”śÂˇculo de tracciâ”śâ”‚n animal a la rutinaria ruta de distribuciâ”śâ”‚n.', 1901, 1901, 1901, 'Anos 1900', 'CENTRO', 41.65217000, -0.88071800, '0101000020E6100000F1F3DF83D72EECBF56B77A4E7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34381046075.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34381046075.webp', 'https://www.flickr.com/photos/zaragozaantigua/34381046075/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24922, 'Muralla romana 2008', 'Restos de un torreâ”śâ”‚n de la muralla romana de Caesaraugusta, en la calle de los Mâ”śĂ­rtires 2 y 4 (izquierda). El edificio que se levanta ahora allâ”śÂˇ los conserva a la vista en su interior. Fuente: arqueoguti.wordpress.com/2010/11/14/documentacion-geometr...', 2008, 2008, 2008, 'Siglo XXI', 'CENTRO', 41.65238900, -0.88047400, '0101000020E6100000444E5FCFD72CECBF94A2957B81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33197053611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33197053611.webp', 'https://www.flickr.com/photos/zaragozaantigua/33197053611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25090, 'Santa Engracia 303', '"Ademâ”śĂ­s de los innumerables mâ”śĂ­rtires que padecieron en la persecuciâ”śâ”‚n de Diocleciano, sufriâ”śâ”‚ el martirio santa Engracia, natural de Zaragoza, con sus 18 compaâ”śâ–’eros, por los aâ”śâ–’os de 303", grabado de Mateo Gonzâ”śĂ­lez, 1788. Al fondo, representaciâ”śâ”‚n de la muralla con la primitiva puerta sur, luego Cinegia. Fuente: lasfotosdebeatrizbm.blogspot.com', NULL, NULL, NULL, NULL, 'CENTRO', 41.65216200, -0.88075500, '0101000020E61000003A3B191C252FECBFD3D85E0B7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32583023483.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32583023483.webp', 'https://www.flickr.com/photos/zaragozaantigua/32583023483/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25094, 'Plâ”śĂ­cido Domingo 1988', 'El cantante Plâ”śĂ­cido Domingo (Madrid, 1941), en la calle de los Mâ”śĂ­rtires, entrada del Tubo, donde sus abuelos abrieron la fonda La Cocineja, desde 1935 Casa Colâ”śĂ­s. Fuente: Heraldo de Aragâ”śâ”‚n.', 1988, 1988, 1988, 'Anos 80', 'CENTRO', 41.65259800, -0.88039900, '0101000020E61000009BCB0D863A2CECBFAEB7CD5488D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33124352136.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33124352136.webp', 'https://www.flickr.com/photos/zaragozaantigua/33124352136/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25132, 'Convento de San Francisco 1809', '"Place du Cofso a Sarragosse aprâ”śÂżs le Siâ”śÂżge", litografâ”śÂˇa de Engelman sobre dibujo de Bacler D''Albe, 1809. Ruinas del Convento de San Francisco de Zaragoza, bombardeado durante los sitios de 1808 y 1809. Parte de su solar serâ”śĂ­ destinado a la sede de la Diputaciâ”śâ”‚n Provincial de Zaragoza. Fuente: Catâ”śĂ­logo El municipio en Aragâ”śâ”‚n, DPZ, 2004.', 1809, 1809, 1809, 'Siglo XIX', 'CENTRO', 41.65229400, -0.88107500, '0101000020E6100000A857CA32C431ECBF42B0AA5E7ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18680553701.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18680553701.webp', 'https://www.flickr.com/photos/zaragozaantigua/18680553701/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25143, 'Plaza de la Constituciâ”śâ”‚n 1862', 'Dibujo de "Lâ”śâ”‚pez" publicado en el nâ”¬â•‘ 1 de "El Duende" (periâ”śâ”‚dico satâ”śÂˇrico semanal editado en Zaragoza), como litografâ”śÂˇa que ilumina un relato, o tragedia caricaturesca, titulada "La justicia de Neptuno", en la que la versiâ”śâ”‚n local del dios de las aguas la emprende con los guardias municipales ante su pasividad por el tremendo gallinero montado, en torno a los dominios de su fuente en la plaza de la Constituciâ”śâ”‚n, por soldados, aguadores, zagales de diligencias y fregatrices. En primer plano, el episodio de justicia neptuniana. Detrâ”śĂ­s, la vacante fuente rodeada de los alborotadores, que siguen a lo suyo. Al fondo, fachada esquinera de la plaza-Coso Alto, con una parcial vista del nuevo edificio de la Diputaciâ”śâ”‚n, a la izquierda.', 1862, 1862, 1862, 'Siglo XIX', 'CENTRO', 41.65219700, -0.88107500, '0101000020E6100000A857CA32C431ECBF50C6F8307BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24633217091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24633217091.webp', 'https://www.flickr.com/photos/zaragozaantigua/24633217091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25186, 'Puerta Cinegia siglo III', 'Dibujo de Francisco Melâ”śÂ®ndez expuesto en un panel a la entrada del centro comercial Puerta Cinegia, inaugurado en 2004 en la plaza de Espaâ”śâ–’a. Representa la ciudad romana de Caesaragusta, vista en el interior de su muralla del siglo III, con la Puerta Cinegia a la derecha.', 250, 200, 299, 'Siglo XIX', 'CENTRO', 41.65251100, -0.88066500, '0101000020E61000003C6BB75D682EECBFDFA3FE7A85D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52492659400.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52492659400.webp', 'https://www.flickr.com/photos/zaragozaantigua/52492659400/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25273, 'El Tubo 1968', 'Instantâ”śĂ­nea urbana del emboque de la populosa y turâ”śÂˇstica calle de los Mâ”śĂ­rtires con la plaza de Espaâ”śâ–’a al fondo, donde destaca el monumento a los Mâ”śĂ­rtires. Este câ”śÂ®ntrico enclave es conocido como la entrada al pequeâ”śâ–’o barrio del Tubo. En el quiosco de prensa de la derecha, un anuncio: "El Alcâ”śĂ­zar. En directo el mundo entero".', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65237600, -0.88045900, '0101000020E6100000EF004F5AB82CECBFFF58880E81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14965606491.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14965606491.webp', 'https://www.flickr.com/photos/zaragozaantigua/14965606491/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25278, 'Acciâ”śâ”‚n Ciudadana, 1936', 'AHPZ. Archivo Coyne. Manuel Coyne. 1936. "Acciâ”śâ”‚n Ciudadana" en Zaragoza era una organizaciâ”śâ”‚n paramilitar formada el 18 de julio de 1936 por jefes y oficiales del Ejâ”śÂ®rcito retirados por las reformas de Azaâ”śâ–’a que guardaban una calurosa animadversiâ”śâ”‚n hacia la Repâ”śâ•‘blica democrâ”śĂ­tica. Segâ”śâ•‘n la prensa, pronto alcanzaron los 3.000 afiliados. Iban armados y con un brazalete blanco en el brazo izquierdo. Se ocuparon del abastecimiento de la ciudad, y desempeâ”śâ–’aron servicios de vigilancia, protecciâ”śâ”‚n y "limpieza". Tenâ”śÂˇan a gala ser apolâ”śÂˇticos o, lo que es lo mismo, no tener matiz polâ”śÂˇtico alguno, salvo "el honor de servir a Espaâ”śâ–’a en su causa mâ”śĂ­s justa y mâ”śĂ­s noble: la de salvarla de la tiranâ”śÂˇa de Moscâ”śâ•‘". (Heraldo de Aragâ”śâ”‚n, 28-07-1936). En la imagen, personal de la derecha extrema, ultraderechista y de Acciâ”śâ”‚n Ciudadana, en la calle Mâ”śĂ­rtires, muy satisfechos de limpiar el Tubo de rojos e indeseables al nuevo orden.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65237600, -0.88045900, '0101000020E6100000EF004F5AB82CECBFFF58880E81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15023967441.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15023967441.webp', 'https://www.flickr.com/photos/zaragozaantigua/15023967441/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25293, 'Coso-Plaza de Espaâ”śâ–’a 1988', 'Imagen de la fachada del Coso en su tramo de la plaza de Espaâ”śâ–’a, cuando el inicio del piqueteo del tramo de los edificios del nâ”¬â•‘ 35 al 41, junto a la entrada a la calle Mâ”śĂ­rtires (antigua Cinegio). A la izquierda, el nâ”¬â•‘ 33, todavâ”śÂˇa con los sâ”śÂˇmbolos de su larga etapa como sede provincial de Falange. El nâ”¬â•‘ 35, ya con la excavadora en plena acciâ”śâ”‚n, removiendo ruinas. Los nâ”śâ•‘meros 37-39, a la espera, con los reconocibles y visuales anuncios comerciales que los remataban. En los locales de estos edificios, algunos de los comercios de este sector urbano. Al fondo, visible por derribo, el torreâ”śâ”‚n que remata el patio del edificio gâ”śâ”‚tico-mudâ”śÂ®jar de la esquina de Mâ”śĂ­rtires-Cuatro de Agosto.', 1988, 1988, 1988, 'Anos 80', 'CENTRO', 41.65256100, -0.88096600, '0101000020E6100000F969DC9BDF30ECBF91D26C1E87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17043337769.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17043337769.webp', 'https://www.flickr.com/photos/zaragozaantigua/17043337769/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25914, 'P.â”¬â•‘ de Fernando el Catâ”śâ”‚lico 1952', 'Inâ”śÂ®dita imagen capturada en altura desde la novâ”śÂˇsima torre de la marista Editorial Luis Vives SA y centrada en el tramo del paseo de Fernando el Catâ”śâ”‚lico comprendido entre el cruce con las calles de Manuel Serrano Sanz y de Luis Vives (en primer tâ”śÂ®rmino) y la plaza de San Francisco (originalmente de Espaâ”śâ–’a, al fondo, con sus caracterâ”śÂˇsticos porches). En ese momento todavâ”śÂˇa alternaban los recientes edificios de viviendas de este moderno paseo con los solares de inmuebles que aâ”śâ–’os despuâ”śÂ®s serâ”śÂˇan construidos. Asâ”śÂˇ, en el lado de los pares (a la izquierda), figuran los ya terminados nâ”śâ•‘meros 56-48, 44 y 40 (esquinero con la calle de Andrâ”śÂ®s Gimâ”śÂ®nez Soler). En el lado de los impares destaca el inmediato solar esquinero con la calle de Luis Vives (futuro nâ”¬â•‘ 57), medianero con el ya construido nâ”¬â•‘ 55. Traqueteando hacia el principio de lâ”śÂˇnea en la plaza de Espaâ”śâ–’a, una unidad tranviaria de la serie 200 (posiblemente la nâ”¬â•‘ 202) en servicio en la lâ”śÂˇnea 11 "Parque" circula por un luminoso y bien tranquilo paseo. Fuente visual: aportaciâ”śâ”‚n personal y exclusiva de la familia de Sola al Gran Archivo Zaragoza Antigua (GAZA).', 1952, 1952, 1952, 'Anos 50', 'UNIVERSIDAD', 41.63919800, -0.89669300, '0101000020E610000008ABB184B5B1ECBF95D5743DD1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29096294037.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29096294037.webp', 'https://www.flickr.com/photos/zaragozaantigua/29096294037/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25294, 'Pl. de la Constituciâ”śâ”‚n 1928', 'Esos dâ”śÂˇas de mayo, en el aâ”śâ–’o V de la Dictadura de Primo de Rivera, la ciudad era objeto de una enorme fiesta eucarâ”śÂˇstica que culminâ”śâ”‚ con tremendas procesionarias peregrinantes y multinacionales ante la columna que llaman pilar. Hasta el Infante don Fernando de Baviera, de visita a las obras de la AGM y el campo de maniobras de San Gregorio, se apuntâ”śâ”‚ a la fiesta posterior, en la Lonja. En la Imagen, aspecto de la gran procesiâ”śâ”‚n que el dâ”śÂˇa 21 habâ”śÂˇa salido desde la basâ”śÂˇlica concatedral, siguiâ”śâ”‚ por Jaime I, y llegâ”śâ”‚ a la plaza de la Constituciâ”śâ”‚n, donde la foto fue realizada, para continuar luego por el Coso Alto, Alfonso I, y vuelta al Pilar, a misa de las 8 de la tarde. Lo que parece una falla es una valiosa imagen de Marâ”śÂˇa e hijo que se trajeron desde la villa y corte los "caballeros madrileâ”śâ–’os" sobre caballos mecâ”śĂ­nicos. A la izquierda, aspecto de la fachada de los edificios de la plaza, con cartelâ”śâ”‚n del "Gran Cafâ”śÂ® Royalty", establecimiento restaurador de "Lujo y Confort" especializado en cafâ”śÂ®s, licores, cerveza y bocadillos, y que un par de aâ”śâ–’os antes habâ”śÂˇa instalado el primer servicio de "cafâ”śÂ® exprâ”śÂ®s" de la ciudad. Aunque en la publicidad decâ”śÂˇan estar en "plaza de la Constituciâ”śâ”‚n 2", su entrada efectiva era por la calle de los Mâ”śĂ­rtires. A su lado, la sede de "La Voz de Aragâ”śâ”‚n", diario grâ”śĂ­fico que llevaba apenas 3 aâ”śâ–’os funcionando, y que pese a su notable calidad, apenas durarâ”śĂ­ otros 7 aâ”śâ–’os. Un poco mâ”śĂ­s adelante, los bajos de la novâ”śÂˇsima sede central del Banco Zaragozano. Fuente visual: revista "Nuevo Mundo" (Madrid), 1928.', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.65256100, -0.88096600, '0101000020E6100000F969DC9BDF30ECBF91D26C1E87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17284038591.webp', 'https://ktnavne